  val sqsService = new AWSSQSService(credentialsManager, region)
  
  def initializeAllServices(credentialProvider: CredentialProvider): Unit = {
    s3Service.initialize(credentialProvider)
    dynamoDBService.initialize(credentialProvider)
    sqsService.initialize(credentialProvider)
  }
  
  def closeAllServices(): Unit = {
    s3Service.close()
    dynamoDBService.close()
    sqsService.close()
  }
}

object AWSServiceExample {
  def main(args: Array[String]): Unit = {
    val serviceManager = new AWSServiceManager(Region.US_EAST_1)
    
    val credentials = DefaultCredentials()
    serviceManager.initializeAllServices(credentials)
    
    serviceManager.s3Service.listBuckets() match {
      case Success(buckets) => println(s"S3 Buckets: ${buckets.mkString(", ")}")
      case Failure(exception) => println(s"Error listing buckets: ${exception.getMessage}")
    }
    
    serviceManager.dynamoDBService.listTables() match {
      case Success(tables) => println(s"DynamoDB Tables: ${tables.mkString(", ")}")
      case Failure(exception) => println(s"Error listing tables: ${exception.getMessage}")
    }
    
    serviceManager.sqsService.listQueues() match {
      case Success(queues) => println(s"SQS Queues: ${queues.mkString(", ")}")
      case Failure(exception) => println(s"Error listing queues: ${exception.getMessage}")
    }
    
    serviceManager.closeAllServices()
  }
}